CANVAS_JS = """
<canvas id="ocean-canvas"></canvas>
<script>
(function() {
  const canvas = document.getElementById('ocean-canvas');
  if (!canvas) return;
  const ctx = canvas.getContext('2d');
  let W, H;
  const bubbles = [];
  const sharks  = [];

  function resize() { W = canvas.width = window.innerWidth; H = canvas.height = window.innerHeight; }
  window.addEventListener('resize', resize);
  resize();

  for (let i = 0; i < 60; i++) {
    bubbles.push({
      x: Math.random() * 1400, y: Math.random() * 900,
      r: Math.random() * 18 + 4,
      vy: -(Math.random() * 0.6 + 0.2),
      alpha: Math.random() * 0.35 + 0.08,
    });
  }

  for (let i = 0; i < 5; i++) {
    sharks.push({
      x: Math.random() * 1200, y: Math.random() * 600 + 80,
      vx: (Math.random() * 0.5 + 0.3) * (Math.random() < 0.5 ? 1 : -1),
      size: Math.random() * 28 + 18,
      alpha: Math.random() * 0.12 + 0.04,
    });
  }

  function animate() {
    ctx.clearRect(0, 0, W, H);

    bubbles.forEach(b => {
      ctx.beginPath();
      ctx.arc(b.x % W, b.y, b.r, 0, Math.PI * 2);
      const g = ctx.createRadialGradient(b.x % W - b.r*0.3, b.y - b.r*0.3, 0, b.x % W, b.y, b.r);
      g.addColorStop(0, `rgba(180,240,255,${b.alpha * 1.5})`);
      g.addColorStop(1, `rgba(0,150,220,${b.alpha * 0.2})`);
      ctx.fillStyle = g;
      ctx.fill();
      ctx.strokeStyle = `rgba(150,220,255,${b.alpha})`;
      ctx.lineWidth = 0.8;
      ctx.stroke();
      b.y += b.vy;
      if (b.y + b.r < 0) { b.y = H + b.r; b.x = Math.random() * W; }
    });

    sharks.forEach(s => {
      ctx.save();
      ctx.globalAlpha = s.alpha;
      ctx.font = s.size + 'px serif';
      if (s.vx < 0) { ctx.scale(-1, 1); ctx.fillText('🦈', -s.x - s.size, s.y); }
      else          { ctx.fillText('🦈', s.x, s.y); }
      ctx.restore();
      s.x += s.vx;
      if (s.x > W + 80) s.x = -80;
      if (s.x < -80)    s.x = W + 80;
    });

    requestAnimationFrame(animate);
  }
  animate();
})();
</script>
"""

